package com.treeeducation.ioas.task; import com.treeeducation.ioas.audit.*;import com.treeeducation.ioas.auth.UserPrincipal;import com.treeeducation.ioas.common.*;import io.swagger.v3.oas.annotations.*;import io.swagger.v3.oas.annotations.tags.Tag;import jakarta.validation.Valid;import org.springframework.data.domain.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;import java.time.Instant; /** Task APIs for media and operators. */ @RestController @RequestMapping("/api/v1/tasks") @Tag(name="Task",description="媒体任务、运营任务与联动更新") public class TaskController{private final TaskRepository repo;private final AuditLogRepository audits; public TaskController(TaskRepository repo,AuditLogRepository audits){this.repo=repo;this.audits=audits;} @GetMapping("/media") @Operation(summary="媒体任务列表") public ApiResponse<PageResponse<TaskDtos.Response>> media(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.ok(PageResponse.of(repo.findByType(TaskType.media,PageRequest.of(page,size)).map(TaskDtos::of)));} @GetMapping("/operator") @Operation(summary="运营任务列表") public ApiResponse<PageResponse<TaskDtos.Response>> operator(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.ok(PageResponse.of(repo.findByType(TaskType.operator,PageRequest.of(page,size)).map(TaskDtos::of)));} @PatchMapping("/{id}") @Operation(summary="任务联动更新") public ApiResponse<TaskDtos.Response> update(@PathVariable Long id,@Valid @RequestBody TaskDtos.UpdateRequest r,@AuthenticationPrincipal UserPrincipal p){Task t=repo.findById(id).orElseThrow(()->BusinessException.notFound("任务不存在"));t.setStatus(r.status());if(r.assigneeId()!=null)t.setAssigneeId(r.assigneeId());t.setUpdatedAt(Instant.now());repo.save(t);AuditLog log=new AuditLog();log.setAction(AuditAction.update_task);log.setTargetType("task");log.setTargetId(id);log.setActorId(p.id());log.setDetail(r.status().name());audits.save(log);return ApiResponse.ok(TaskDtos.of(t));}}
